<?php
namespace App\Http\Controllers\Api;
use App\Actions\CreateInventoryAdjustmentAction;use App\Models\Project;use App\Services\InventoryService;use Illuminate\Http\Request;use App\Http\Controllers\Controller;
class InventoryController extends Controller{public function index(Project $project,InventoryService $s){$this->authorize('view',$project);return $s->getInventoryTable($project);} public function movements(Project $project){$this->authorize('view',$project);return $project->inventoryMovements()->with('material','tags')->latest('date')->get();} public function adjustment(Request $r,Project $project,CreateInventoryAdjustmentAction $a){$this->authorize('update',$project);$data=$r->validate(['material_id'=>'required|exists:materials,id','date'=>'required|date','quantity'=>'required|numeric|not_in:0','unit_price'=>'nullable|numeric|min:0','amount'=>'nullable|numeric','comment'=>'nullable|string']);return $a->execute($data+['project_id'=>$project->id,'type'=>'adjustment']);}}
